class CredentialManager(config: AwsConfig) {

  private var cachedProvider: Option[AwsCredentialsProvider] = None
  private var assumedRoleExpiry: Option[java.time.Instant] = None

  def getCredentialsProvider: AwsCredentialsProvider = {
    cachedProvider match {
      case Some(provider) if !isExpired => provider
      case _ =>
        val provider = buildCredentialsProvider()
        cachedProvider = Some(provider)
        provider
    }
  }

  private def isExpired: Boolean = {
    assumedRoleExpiry.exists(expiry => java.time.Instant.now().isAfter(expiry.minusSeconds(300)))
  }

  private def buildCredentialsProvider(): AwsCredentialsProvider = {
    config.credentialMode match {
      case DefaultCredentials =>
        DefaultCredentialsProvider.create()

      case StaticCredentials(accessKeyId, secretAccessKey) =>
        StaticCredentialsProvider.create(
          AwsBasicCredentials.create(accessKeyId, secretAccessKey)
        )

      case SessionCredentials(accessKeyId, secretAccessKey, sessionToken) =>
        StaticCredentialsProvider.create(
          AwsSessionCredentials.create(accessKeyId, secretAccessKey, sessionToken)
        )

      case ProfileCredentials(profileName) =>
        ProfileCredentialsProvider.create(profileName)

      case AssumeRoleCredentials(roleArn, sessionName) =>
        assumeRole(roleArn, sessionName)
    }
  }

  private def assumeRole(roleArn: String, sessionName: String): AwsCredentialsProvider = {
    val stsClient = StsClient.builder()
      .region(config.region)
      .credentialsProvider(DefaultCredentialsProvider.create())
      .build()

    try {
      val request = AssumeRoleRequest.builder()
        .roleArn(roleArn)
        .roleSessionName(sessionName)
        .durationSeconds(3600)
        .build()

      val response = stsClient.assumeRole(request)
      val credentials = response.credentials()

      assumedRoleExpiry = Some(credentials.expiration())

      StaticCredentialsProvider.create(
        AwsSessionCredentials.create(
          credentials.accessKeyId(),
          credentials.secretAccessKey(),
          credentials.sessionToken()
        )
      )
    } finally {
      stsClient.close()
    }
  }

  def refreshCredentials(): AwsCredentialsProvider = {
    cachedProvider = None
    assumedRoleExpiry = None
    getCredentialsProvider
  }
}

