  lazy val sqs: SQSService = new SQSService(credentialManager, config.region)

  def validateCredentials(): Try[String] = Try {
    val stsClient = StsClient.builder()
      .region(config.region)
      .credentialsProvider(credentialManager.getCredentialsProvider)
      .build()

    try {
      val response = stsClient.getCallerIdentity()
      s"Authenticated as: Account=${response.account()}, ARN=${response.arn()}, UserId=${response.userId()}"
    } finally {
      stsClient.close()
    }
  }

  def refreshAllCredentials(): Unit = {
    credentialManager.refreshCredentials()
  }

  def closeAll(): Unit = {
    Try(s3.close())
    Try(dynamoDB.close())
    Try(sqs.close())
  }
}

